'use client';

import { AddCustomerDialog, EditCustomerDialog } from "@/components/customers/CustomerForm";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Skeleton } from "@/components/ui/skeleton";
import { Switch } from "@/components/ui/switch";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import { useOnlineStatus } from "@/hooks/use-offline-data";
import { deleteCustomer } from "@/lib/actions/customer.actions";
import { getAllCustomers } from "@/offline/offline-service";
import { CloudOff, Eye, RefreshCw, Search, Trash2 } from "lucide-react";
import { useTranslations } from "next-intl";
import { useRouter } from "next/navigation";
import { useCallback, useEffect, useRef, useState, useTransition } from "react";
import { toast } from "sonner";
import { useDebounce } from "use-debounce";

interface Customer {
    id: string;
    name: string;
    phone: string;
    cnic: string | null;
    address: string | null;
    outstandingAmount: number;
    paidAmount: number;
    isActive: boolean;
}

interface CustomerApiRecord {
    id: string;
    name: string;
    phone: string;
    cnic: string | null;
    address: string | null;
    outstandingAmount: string | number | null;
    paidAmount: string | number | null;
    isActive: boolean;
}

interface CustomerPageResponse {
    data: CustomerApiRecord[];
    nextCursor: string | null;
    totalCount: number;
}

interface CustomerPage {
    customers: Customer[];
    nextCursor: string | null;
    totalCount: number;
}

function mapCustomer(customer: CustomerApiRecord): Customer {
    return {
        id: customer.id,
        name: customer.name,
        phone: customer.phone,
        cnic: customer.cnic,
        address: customer.address || null,
        outstandingAmount: Number(customer.outstandingAmount || 0),
        paidAmount: Number(customer.paidAmount || 0),
        isActive: customer.isActive,
    };
}

function CustomersSkeletonRow() {
    return (
        <TableRow>
            <TableCell><Skeleton className="h-4 w-32" /></TableCell>
            <TableCell><Skeleton className="h-4 w-24" /></TableCell>
            <TableCell><Skeleton className="h-4 w-28" /></TableCell>
            <TableCell className="text-right"><Skeleton className="h-4 w-20 ml-auto" /></TableCell>
            <TableCell className="text-right"><Skeleton className="h-4 w-20 ml-auto" /></TableCell>
            <TableCell className="text-right">
                <div className="flex justify-end gap-1">
                    <Skeleton className="h-8 w-8 rounded-md" />
                    <Skeleton className="h-8 w-8 rounded-md" />
                    <Skeleton className="h-8 w-8 rounded-md" />
                </div>
            </TableCell>
        </TableRow>
    );
}

export function CustomersClient() {
    const router = useRouter();
    const isOnline = useOnlineStatus();
    const t = useTranslations("customers");
    const tc = useTranslations("common");
    const [isPending, startTransition] = useTransition();

    const [deleteTarget, setDeleteTarget] = useState<Customer | null>(null);
    const [searchQuery, setSearchQuery] = useState("");
    const [debouncedSearch] = useDebounce(searchQuery, 350);
    const [outstandingOnly, setOutstandingOnly] = useState(false);
    const [customers, setCustomers] = useState<Customer[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isLoadingMore, setIsLoadingMore] = useState(false);
    const [isOffline, setIsOffline] = useState(false);
    const [nextCursor, setNextCursor] = useState<string | null>(null);
    const [totalCount, setTotalCount] = useState(0);

    const sentinelRef = useRef<HTMLDivElement>(null);
    const requestIdRef = useRef(0);
    const loadingMoreRef = useRef(false);

    const fetchServerPage = useCallback(async (
        search: string,
        outstanding: boolean,
        cursor: string | null
    ): Promise<CustomerPage> => {
        const params = new URLSearchParams();
        const trimmedSearch = search.trim();
        if (trimmedSearch) params.set("q", trimmedSearch);
        if (cursor) params.set("cursor", cursor);
        if (outstanding) params.set("outstanding", "true");
        params.set("_t", Date.now().toString());

        const response = await fetch(`/api/customers?${params.toString()}`, { cache: "no-store" });
        if (!response.ok) throw new Error("Failed to fetch customers");

        const json = await response.json() as CustomerPageResponse;
        return {
            customers: (json.data || []).map(mapCustomer),
            nextCursor: json.nextCursor || null,
            totalCount: Number(json.totalCount || 0),
        };
    }, []);

    const fetchOfflineCustomers = useCallback(async (
        search: string,
        outstanding: boolean
    ): Promise<CustomerPage> => {
        const offlineCustomers = await getAllCustomers();
        const q = search.trim().toLowerCase();

        const filtered = offlineCustomers
            .filter(customer => customer.isActive)
            .filter(customer => {
                if (!q) return true;

                return (
                    customer.name.toLowerCase().includes(q) ||
                    customer.phone.toLowerCase().includes(q) ||
                    (customer.cnic?.toLowerCase().includes(q) ?? false)
                );
            })
            .filter(customer => !outstanding || customer.outstandingAmount > 0)
            .sort((a, b) => {
                const nameOrder = a.name.localeCompare(b.name, undefined, { sensitivity: "base" });
                return nameOrder || a.id.localeCompare(b.id);
            })
            .map(customer => ({
                id: customer.id,
                name: customer.name,
                phone: customer.phone,
                cnic: customer.cnic,
                address: customer.address || null,
                outstandingAmount: customer.outstandingAmount,
                paidAmount: customer.paidAmount,
                isActive: customer.isActive,
            }));

        return {
            customers: filtered,
            nextCursor: null,
            totalCount: filtered.length,
        };
    }, []);

    const loadFirstPage = useCallback(async (search: string, outstanding: boolean) => {
        const requestId = requestIdRef.current + 1;
        requestIdRef.current = requestId;
        loadingMoreRef.current = false;

        setIsLoading(true);
        setCustomers([]);
        setNextCursor(null);
        setTotalCount(0);

        try {
            const page = isOnline
                ? await fetchServerPage(search, outstanding, null)
                : await fetchOfflineCustomers(search, outstanding);

            if (requestIdRef.current !== requestId) return;

            setIsOffline(!isOnline);
            setCustomers(page.customers);
            setNextCursor(page.nextCursor);
            setTotalCount(page.totalCount);
        } catch (error) {
            console.warn("Server fetch failed, falling back to offline customers:", error);

            try {
                const page = await fetchOfflineCustomers(search, outstanding);
                if (requestIdRef.current !== requestId) return;

                setIsOffline(true);
                setCustomers(page.customers);
                setNextCursor(null);
                setTotalCount(page.totalCount);
            } catch (offlineError) {
                console.error("Failed to load customers:", offlineError);
                if (requestIdRef.current !== requestId) return;

                setIsOffline(!isOnline);
                setCustomers([]);
                setNextCursor(null);
                setTotalCount(0);
            }
        } finally {
            if (requestIdRef.current === requestId) {
                setIsLoading(false);
            }
        }
    }, [fetchOfflineCustomers, fetchServerPage, isOnline]);

    useEffect(() => {
        void loadFirstPage(debouncedSearch, outstandingOnly);
    }, [debouncedSearch, loadFirstPage, outstandingOnly]);

    const loadMore = useCallback(async () => {
        if (loadingMoreRef.current || isLoading || isOffline || !nextCursor) return;

        loadingMoreRef.current = true;
        setIsLoadingMore(true);

        try {
            const page = await fetchServerPage(debouncedSearch, outstandingOnly, nextCursor);
            setCustomers(previous => {
                const seenIds = new Set(previous.map(customer => customer.id));
                const merged = [...previous];

                for (const customer of page.customers) {
                    if (!seenIds.has(customer.id)) {
                        seenIds.add(customer.id);
                        merged.push(customer);
                    }
                }

                return merged;
            });
            setNextCursor(page.nextCursor);
            setTotalCount(page.totalCount);
        } catch (error) {
            console.error("Failed to load more customers:", error);
        } finally {
            loadingMoreRef.current = false;
            setIsLoadingMore(false);
        }
    }, [debouncedSearch, fetchServerPage, isLoading, isOffline, nextCursor, outstandingOnly]);

    useEffect(() => {
        const sentinel = sentinelRef.current;
        if (!sentinel) return;

        const observer = new IntersectionObserver(
            (entries) => {
                if (entries[0]?.isIntersecting) {
                    void loadMore();
                }
            },
            { threshold: 0.1 }
        );

        observer.observe(sentinel);
        return () => observer.disconnect();
    }, [loadMore]);

    const refetch = () => {
        void loadFirstPage(debouncedSearch, outstandingOnly);
    };

    const handleDeactivate = () => {
        if (!deleteTarget) return;
        startTransition(async () => {
            const result = await deleteCustomer(deleteTarget.id);
            if (result.success) {
                toast.success(t("customerDeactivated"));
                router.refresh();
                void loadFirstPage(debouncedSearch, outstandingOnly);
            } else {
                toast.error(result.error || "Failed to deactivate customer");
            }
            setDeleteTarget(null);
        });
    };

    return (
        <>
            <div className="space-y-6">
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <h2 className="text-3xl font-bold tracking-tight">{t("title")}</h2>
                        {isOffline && (
                            <Badge variant="outline" className="text-yellow-600 border-yellow-600">
                                <CloudOff className="h-3 w-3 mr-1" />
                                {tc("offlineData")}
                            </Badge>
                        )}
                    </div>
                    <div className="flex items-center gap-2">
                        <Button variant="outline" size="icon" onClick={refetch} disabled={!isOnline || isLoading}>
                            <RefreshCw className="h-4 w-4" />
                        </Button>
                        {!isOffline && <AddCustomerDialog />}
                    </div>
                </div>

                <Card>
                    <CardHeader className="gap-4">
                        <div className="flex flex-col gap-1 sm:flex-row sm:items-center sm:justify-between">
                            <CardTitle>{t("customerList")}</CardTitle>
                            {!isLoading && customers.length > 0 && (
                                <p className="text-sm text-muted-foreground">
                                    {tc("showing")} {customers.length} {tc("of")} {totalCount} {tc("entries")}
                                </p>
                            )}
                        </div>
                        <div className="flex flex-col gap-3 sm:flex-row sm:items-center">
                            <div className="relative w-full sm:max-w-sm">
                                <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                                <Input
                                    placeholder="Search by name, phone, or CNIC..."
                                    value={searchQuery}
                                    onChange={(event) => setSearchQuery(event.target.value)}
                                    className="pl-9"
                                />
                            </div>
                            <Label className="h-9 w-full justify-between rounded-md border px-3 sm:w-auto sm:justify-start">
                                <Switch
                                    checked={outstandingOnly}
                                    onCheckedChange={setOutstandingOnly}
                                    size="sm"
                                />
                                <span>{t("outstandingAmount")} only</span>
                            </Label>
                        </div>
                    </CardHeader>
                    <CardContent>
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>{tc("name")}</TableHead>
                                    <TableHead>{t("phone")}</TableHead>
                                    <TableHead>{t("cnic")}</TableHead>
                                    <TableHead className="text-right">{t("paidAmount")}</TableHead>
                                    <TableHead className="text-right">{t("outstandingAmount")}</TableHead>
                                    <TableHead className="text-right">{tc("actions")}</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {isLoading ? (
                                    [...Array(6)].map((_, i) => <CustomersSkeletonRow key={i} />)
                                ) : customers.length === 0 ? (
                                    <TableRow>
                                        <TableCell colSpan={6} className="text-center h-24">
                                            {t("noCustomersFound")}
                                        </TableCell>
                                    </TableRow>
                                ) : (
                                    <>
                                        {customers.map((customer) => (
                                            <TableRow key={customer.id}>
                                                <TableCell className="font-medium">{customer.name}</TableCell>
                                                <TableCell>{customer.phone}</TableCell>
                                                <TableCell>{customer.cnic || '—'}</TableCell>
                                                <TableCell className="text-right text-green-600">
                                                    Rs. {customer.paidAmount.toLocaleString()}
                                                </TableCell>
                                                <TableCell className={`text-right ${customer.outstandingAmount > 0 ? "text-red-500 font-bold" : "text-green-600"}`}>
                                                    Rs. {customer.outstandingAmount.toLocaleString()}
                                                </TableCell>
                                                <TableCell className="text-right">
                                                    <div className="flex items-center justify-end gap-1">
                                                        <Button
                                                            variant="ghost"
                                                            size="icon"
                                                            title={t("customerDetails")}
                                                            onClick={() => router.push(`/customers/${customer.id}`)}
                                                        >
                                                            <Eye className="h-4 w-4" />
                                                        </Button>
                                                        {!isOffline && (
                                                            <>
                                                                <EditCustomerDialog customer={customer} />
                                                                <Button
                                                                    variant="ghost"
                                                                    size="icon"
                                                                    className="text-destructive hover:text-destructive"
                                                                    title={t("deactivateCustomer")}
                                                                    onClick={() => setDeleteTarget(customer)}
                                                                >
                                                                    <Trash2 className="h-4 w-4" />
                                                                </Button>
                                                            </>
                                                        )}
                                                    </div>
                                                </TableCell>
                                            </TableRow>
                                        ))}
                                        {isLoadingMore && [...Array(4)].map((_, i) => <CustomersSkeletonRow key={`more-${i}`} />)}
                                    </>
                                )}
                            </TableBody>
                        </Table>
                        <div ref={sentinelRef} className="h-4" />
                    </CardContent>
                </Card>
            </div>

            <AlertDialog
                open={!!deleteTarget}
                onOpenChange={(val) => {
                    if (!val) setDeleteTarget(null);
                }}
            >
                <AlertDialogContent>
                    <AlertDialogHeader>
                        <AlertDialogTitle>{t("deactivateCustomer")}</AlertDialogTitle>
                        <AlertDialogDescription>
                            {t("confirmDeactivateCustomer", { name: deleteTarget?.name || "" })}
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter>
                        <AlertDialogCancel>{tc("cancel")}</AlertDialogCancel>
                        <AlertDialogAction
                            onClick={handleDeactivate}
                            disabled={isPending}
                            className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
                        >
                            {isPending ? tc("loading") : tc("confirm")}
                        </AlertDialogAction>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>
        </>
    );
}

