import { db } from "@/db";
import { customers } from "@/db/schema";
import { and, asc, eq, gt, ilike, or, sql, type SQL } from "drizzle-orm";
import { NextRequest, NextResponse } from "next/server";

const PAGE_SIZE = 50;

type CustomerRow = typeof customers.$inferSelect;

interface CustomerCursor {
    name: string;
    id: string;
}

function encodeCursor(customer: CustomerRow): string {
    return Buffer.from(
        JSON.stringify({
            name: customer.name.toLowerCase(),
            id: customer.id,
        } satisfies CustomerCursor)
    ).toString("base64url");
}

function decodeCursor(cursor: string | null): CustomerCursor | null {
    if (!cursor) return null;

    try {
        const parsed = JSON.parse(Buffer.from(cursor, "base64url").toString("utf8")) as Partial<CustomerCursor>;
        if (typeof parsed.name !== "string" || typeof parsed.id !== "string") {
            return null;
        }

        return {
            name: parsed.name.toLowerCase(),
            id: parsed.id,
        };
    } catch {
        return null;
    }
}

function combineConditions(conditions: SQL[]): SQL {
    const clause = and(...conditions);
    if (!clause) {
        throw new Error("Expected at least one customer query condition");
    }
    return clause;
}

export async function GET(req: NextRequest) {
    const { searchParams } = new URL(req.url);
    const query = searchParams.get("q")?.trim() ?? "";
    const cursorParam = searchParams.get("cursor");
    const cursor = decodeCursor(cursorParam);
    const outstandingOnly = searchParams.get("outstanding") === "true";

    if (cursorParam && !cursor) {
        return NextResponse.json({ error: "Invalid cursor" }, { status: 400 });
    }

    try {
        const filterConditions: SQL[] = [eq(customers.isActive, true)];

        if (query.length > 0) {
            const searchPattern = `%${query}%`;
            filterConditions.push(
                or(
                    ilike(customers.name, searchPattern),
                    ilike(customers.phone, searchPattern),
                    ilike(customers.cnic, searchPattern)
                )!
            );
        }

        if (outstandingOnly) {
            filterConditions.push(gt(customers.outstandingAmount, "0"));
        }

        const filteredWhere = combineConditions(filterConditions);
        const cursorConditions = [...filterConditions];

        if (cursor) {
            cursorConditions.push(sql`
                (
                    lower(${customers.name}) > ${cursor.name}
                    OR (
                        lower(${customers.name}) = ${cursor.name}
                        AND ${customers.id} > ${cursor.id}
                    )
                )
            `);
        }

        const pagedWhere = combineConditions(cursorConditions);
        const nameSort = sql<string>`lower(${customers.name})`;

        const [rows, [{ count }]] = await Promise.all([
            db
                .select()
                .from(customers)
                .where(pagedWhere)
                .orderBy(asc(nameSort), asc(customers.id))
                .limit(PAGE_SIZE + 1),
            db
                .select({ count: sql<number>`count(*)::int` })
                .from(customers)
                .where(filteredWhere),
        ]);

        const data = rows.slice(0, PAGE_SIZE);
        const nextCursor = rows.length > PAGE_SIZE && data.length > 0 ? encodeCursor(data[data.length - 1]) : null;

        return NextResponse.json({
            data,
            nextCursor,
            totalCount: count,
        });
    } catch (error) {
        console.error("Customers API Error:", error);
        return NextResponse.json({ error: "Failed to fetch customers" }, { status: 500 });
    }
}

